#!/usr/bin/env node

/**
 * 定时笑话发送脚本
 * 每隔 1 分钟发送一个笑话，共 10 次
 */

const { exec } = require('child_process');
const path = require('path');

const jokes = [
    "有一天，0 在街上遇到了 8，0 不屑地看了 8 一眼，说：'胖就胖呗，还系什么腰带啊！'",
    "程序员最讨厌康熙的哪个儿子？胤禛（因为赢在起点）",
    "为什么程序员总是分不清万圣节和圣诞节？因为 Oct 31 == Dec 25！",
    "有个程序员去相亲，女方问：'你有房吗？' 程序员说：'有啊，我住在 GitHub 上。'",
    "程序员的妻子让他去买包子，说：'如果看到西瓜，就买一个。' 结果他买了一个包子回来，因为看到了西瓜。",
    "为什么程序员不喜欢出门？因为他们可能会被树困住（因为树 = tree = 递归）",
    "程序员的闹钟响了，他按掉继续睡，因为他的代码里写的是 while(alive) { sleep(); }",
    "有个程序员对老婆说：'亲爱的，我去趟超市，如果看到卖草莓的，就买一斤。' 过了一会儿他回来了，手里拿着一斤草莓。老婆问：'你怎么买了？' 程序员说：'因为我看到卖草莓的了啊。'",
    "为什么程序员总是找不到对象？因为他们总是在找 bug。",
    "程序员的遗言：'我...我还有...一个 bug...没 fix...'"
];

let count = 0;
const maxCount = 10;
const intervalMs = 60 * 1000; // 1 分钟

// 目标：私聊发送到 manager20（陈玺翔的 staffId）
const target = 'manager20';
const channel = 'clawdbot-dingtalk';

function sendJoke(joke, index) {
    return new Promise((resolve, reject) => {
        const message = `@陈玺翔 笑话 #${index + 1}/10：${joke} 😄`;
        const cmd = `openclaw message send --channel ${channel} --target ${target} --message "${message.replace(/"/g, '\\"')}"`;

        console.log(`[${new Date().toISOString()}] 发送笑话 #${index + 1}: ${joke.substring(0, 30)}...`);

        exec(cmd, (error, stdout, stderr) => {
            if (error) {
                console.error(`发送失败：${error.message}`);
                reject(error);
            } else {
                console.log(`发送成功！`);
                resolve({ stdout, stderr });
            }
        });
    });
}

async function run() {
    console.log('🚀 定时笑话脚本启动！');
    console.log(`📍 目标：${target}`);
    console.log(`📺 渠道：${channel}`);
    console.log(`⏱️ 间隔：${intervalMs / 1000}秒`);
    console.log(`🔢 次数：${maxCount}次`);
    console.log('---');

    for (let i = 0; i < maxCount; i++) {
        try {
            await sendJoke(jokes[i], i);
            count++;

            if (i < maxCount - 1) {
                console.log(`⏳ 等待 ${intervalMs / 1000}秒后发送下一个...`);
                await new Promise(resolve => setTimeout(resolve, intervalMs));
            }
        } catch (error) {
            console.error(`❌ 发送失败：${error.message}`);
        }
    }

    console.log('---');
    console.log('✅ 完成！共发送 ${count} 个笑话');

    // 发送结束消息
    await sendJoke('笑话连播结束啦！希望你今天开心！😄', 99);
}

run().catch(console.error);

